import React, { useState } from 'react';
import axios from 'axios';
import { useNavigate } from 'react-router-dom';

const s = {
  page: { padding: 32, maxWidth: 680, margin: '0 auto' },
  card: { background: '#fff', borderRadius: 16, padding: '36px', boxShadow: '0 4px 20px rgba(0,0,0,0.08)', marginBottom: 20 },
  title: { fontSize: 22, fontWeight: 700, color: '#1a3a5c', marginBottom: 6 },
  subtitle: { fontSize: 13, color: '#888', marginBottom: 24 },
  sectionTitle: { fontSize: 15, fontWeight: 700, color: '#1a3a5c', marginBottom: 14, paddingBottom: 8, borderBottom: '2px solid #e8f0fe' },
  label: { display: 'block', fontSize: 13, fontWeight: 600, color: '#444', marginBottom: 6 },
  input: { width: '100%', padding: '11px 14px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 15, outline: 'none', marginBottom: 18, boxSizing: 'border-box' },
  select: { width: '100%', padding: '11px 14px', border: '1.5px solid #ddd', borderRadius: 8, fontSize: 15, outline: 'none', marginBottom: 18, background: '#fff', boxSizing: 'border-box' },
  grid: { display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 16 },
  btn: { width: '100%', padding: '14px', background: '#1a3a5c', color: '#fff', border: 'none', borderRadius: 8, fontSize: 16, fontWeight: 700, cursor: 'pointer', marginTop: 8 },
  err: { background: '#fdecea', color: '#c0392b', padding: 12, borderRadius: 8, marginBottom: 16, fontSize: 14 },
  success: { background: '#eafaf1', color: '#27ae60', padding: 14, borderRadius: 8, marginBottom: 16, fontSize: 14, fontWeight: 600 },
  uploadBox: { border: '2px dashed #c0d4f0', borderRadius: 10, padding: '18px 16px', marginBottom: 18, background: '#f8fbff', cursor: 'pointer', textAlign: 'center', transition: 'border 0.2s' },
  uploadLabel: { fontSize: 13, color: '#2980b9', fontWeight: 600, cursor: 'pointer' },
  fileInfo: { fontSize: 12, color: '#27ae60', marginTop: 6, fontWeight: 600 },
  aiBox: { borderRadius: 10, padding: 16, marginBottom: 18, fontSize: 13 },
  aiChecking: { background: '#fff8e1', border: '1.5px solid #f39c12', color: '#856404' },
  aiPass: { background: '#eafaf1', border: '1.5px solid #27ae60', color: '#155724' },
  aiFail: { background: '#fdecea', border: '1.5px solid #e74c3c', color: '#721c24' },
  stepRow: { display: 'flex', alignItems: 'center', gap: 10, marginBottom: 10 },
  stepCircle: { width: 28, height: 28, borderRadius: '50%', display: 'flex', alignItems: 'center', justifyContent: 'center', fontSize: 13, fontWeight: 700, flexShrink: 0 },
};

const DOC_TYPES = [
  { key: 'aadhar', label: 'Aadhar Card', icon: '🪪', hint: 'Upload front side of Aadhar card (JPG/PNG/PDF)' },
  { key: 'fees', label: 'Fees Receipt', icon: '🧾', hint: 'Latest semester fees receipt from college' },
  { key: 'collegeId', label: 'College ID', icon: '🎓', hint: 'Front side of your NIE college ID card' },
];

function toBase64(file) {
  return new Promise((res, rej) => {
    const r = new FileReader();
    r.onload = () => res(r.result.split(',')[1]);
    r.onerror = rej;
    r.readAsDataURL(file);
  });
}

async function verifyDocumentWithAI(file, docType) {
  const base64 = await toBase64(file);
  const mediaType = file.type || 'image/jpeg';

  const prompt = `You are a document verification assistant for a college bus pass system at NIE Mysuru.

The student has uploaded a document claiming to be: "${docType}"

Analyze this image and respond in JSON only (no markdown, no extra text):
{
  "valid": true or false,
  "confidence": "high" or "medium" or "low",
  "documentDetected": "what you see in the image",
  "issues": "any issues found or empty string",
  "suggestion": "brief message to student"
}

Rules:
- For "Aadhar Card": look for Aadhar number pattern, UIDAI logo, or government ID layout
- For "Fees Receipt": look for college name, amount, receipt number, date
- For "College ID": look for college name, student photo, ID card layout
- If image is blurry, wrong document, or unclear mark valid as false`;

  const response = await fetch('https://api.anthropic.com/v1/messages', {
    method: 'POST',
    headers: { 'Content-Type': 'application/json' },
    body: JSON.stringify({
      model: 'claude-sonnet-4-20250514',
      max_tokens: 1000,
      messages: [{
        role: 'user',
        content: [
          { type: 'image', source: { type: 'base64', media_type: mediaType, data: base64 } },
          { type: 'text', text: prompt }
        ]
      }]
    })
  });

  const data = await response.json();
  const text = data.content?.[0]?.text || '{}';
  try {
    const clean = text.replace(/```json|```/g, '').trim();
    return JSON.parse(clean);
  } catch {
    return { valid: false, confidence: 'low', documentDetected: 'Unknown', issues: 'Could not parse document', suggestion: 'Please re-upload a clear image' };
  }
}

export default function ApplyPass() {
  const [form, setForm] = useState({ from: '', to: '', passType: 'monthly', studentName: '', mobile: '', address: '' });
  const [files, setFiles] = useState({ aadhar: null, fees: null, collegeId: null });
  const [aiResults, setAiResults] = useState({ aadhar: null, fees: null, collegeId: null });
  const [aiLoading, setAiLoading] = useState({ aadhar: false, fees: false, collegeId: false });
  const [error, setError] = useState('');
  const [success, setSuccess] = useState('');
  const [loading, setLoading] = useState(false);
  const navigate = useNavigate();

  const set = (k) => (e) => setForm({ ...form, [k]: e.target.value });

  const handleFileUpload = async (docKey, file) => {
    if (!file) return;
    setFiles(prev => ({ ...prev, [docKey]: file }));
    setAiResults(prev => ({ ...prev, [docKey]: null }));
    setAiLoading(prev => ({ ...prev, [docKey]: true }));

    const docLabel = DOC_TYPES.find(d => d.key === docKey)?.label;
    try {
      const result = await verifyDocumentWithAI(file, docLabel);
      setAiResults(prev => ({ ...prev, [docKey]: result }));
    } catch (e) {
      setAiResults(prev => ({ ...prev, [docKey]: { valid: false, suggestion: 'Verification failed, please re-upload' } }));
    }
    setAiLoading(prev => ({ ...prev, [docKey]: false }));
  };

  const allDocsVerified = DOC_TYPES.every(d => aiResults[d.key]?.valid === true);
  const anyDocFailed = DOC_TYPES.some(d => aiResults[d.key]?.valid === false);

  const handleSubmit = async (e) => {
    e.preventDefault();
    if (!allDocsVerified) { setError('Please upload and verify all 3 documents before submitting.'); return; }
    setError(''); setSuccess(''); setLoading(true);
    try {
      await axios.post('/api/pass/apply', form);
      setSuccess('✅ Application submitted with verified documents! Awaiting admin approval.');
      setTimeout(() => navigate('/my-passes'), 2500);
    } catch (err) {
      setError(err.response?.data?.message || 'Application failed');
    }
    setLoading(false);
  };

  return (
    <div style={s.page}>
      {/* Header */}
      <div style={s.card}>
        <div style={s.title}>🎫 Apply for Bus Pass</div>
        <div style={s.subtitle}>Fill all details and upload required documents for verification</div>

        {/* Steps */}
        {[['1', '#2980b9', 'Fill personal & route details'],
          ['2', '#8e44ad', 'Upload & AI-verify documents'],
          ['3', '#27ae60', 'Submit application']].map(([num, color, text]) => (
          <div key={num} style={s.stepRow}>
            <div style={{ ...s.stepCircle, background: color, color: '#fff' }}>{num}</div>
            <span style={{ fontSize: 13, color: '#555' }}>{text}</span>
          </div>
        ))}
      </div>

      <form onSubmit={handleSubmit}>
        {/* Step 1 - Details */}
        <div style={s.card}>
          <div style={s.sectionTitle}>📋 Step 1 — Personal & Route Details</div>
          {error && <div style={s.err}>{error}</div>}
          {success && <div style={s.success}>{success}</div>}

          <div style={s.grid}>
            <div>
              <label style={s.label}>Full Name</label>
              <input style={s.input} value={form.studentName} onChange={set('studentName')} required placeholder="As on Aadhar card" />
            </div>
            <div>
              <label style={s.label}>Mobile Number</label>
              <input style={s.input} value={form.mobile} onChange={set('mobile')} required placeholder="10-digit mobile" />
            </div>
          </div>

          <label style={s.label}>Home Address</label>
          <input style={s.input} value={form.address} onChange={set('address')} required placeholder="Full home address" />

          <div style={s.grid}>
            <div>
              <label style={s.label}>From (Boarding Point)</label>
              <input style={s.input} value={form.from} onChange={set('from')} required placeholder="e.g. Kuvempunagar" />
            </div>
            <div>
              <label style={s.label}>To (Destination)</label>
              <input style={s.input} value={form.to} onChange={set('to')} required placeholder="e.g. NIE College" />
            </div>
          </div>

          <label style={s.label}>Pass Type</label>
          <select style={s.select} value={form.passType} onChange={set('passType')}>
            <option value="monthly">Monthly (1 month)</option>
            <option value="quarterly">Quarterly (3 months)</option>
            <option value="yearly">Yearly (12 months)</option>
          </select>
        </div>

        {/* Step 2 - Documents */}
        <div style={s.card}>
          <div style={s.sectionTitle}>🤖 Step 2 — Upload & AI Verify Documents</div>
          <p style={{ fontSize: 13, color: '#888', marginBottom: 20 }}>Each document is automatically verified using AI. All 3 must pass before you can submit.</p>

          {DOC_TYPES.map(doc => (
            <div key={doc.key} style={{ marginBottom: 20 }}>
              <label style={s.label}>{doc.icon} {doc.label} <span style={{ color: '#e74c3c' }}>*</span></label>
              <p style={{ fontSize: 12, color: '#aaa', marginBottom: 8 }}>{doc.hint}</p>

              <label style={s.uploadBox}>
                <div style={{ fontSize: 24, marginBottom: 4 }}>📎</div>
                <div style={s.uploadLabel}>
                  {files[doc.key] ? `✅ ${files[doc.key].name}` : `Click to upload ${doc.label}`}
                </div>
                <div style={{ fontSize: 11, color: '#aaa', marginTop: 4 }}>JPG, PNG or PDF — max 5MB</div>
                <input type="file" accept="image/*,.pdf" style={{ display: 'none' }}
                  onChange={e => handleFileUpload(doc.key, e.target.files[0])} />
              </label>

              {/* AI Status */}
              {aiLoading[doc.key] && (
                <div style={{ ...s.aiBox, ...s.aiChecking }}>
                  <strong>🤖 AI Verifying...</strong> Analyzing your {doc.label}, please wait...
                </div>
              )}
              {aiResults[doc.key] && !aiLoading[doc.key] && (
                <div style={{ ...s.aiBox, ...(aiResults[doc.key].valid ? s.aiPass : s.aiFail) }}>
                  <strong>{aiResults[doc.key].valid ? '✅ Verified' : '❌ Verification Failed'}</strong>
                  {' — '}{aiResults[doc.key].documentDetected && <span>Detected: <em>{aiResults[doc.key].documentDetected}</em>. </span>}
                  {aiResults[doc.key].suggestion}
                  {aiResults[doc.key].issues && <div style={{ marginTop: 4, fontSize: 12 }}>Issue: {aiResults[doc.key].issues}</div>}
                </div>
              )}
            </div>
          ))}

          {/* Overall status */}
          {allDocsVerified && (
            <div style={{ background: '#eafaf1', border: '2px solid #27ae60', borderRadius: 10, padding: 14, textAlign: 'center', fontWeight: 700, color: '#27ae60', fontSize: 15 }}>
              ✅ All documents verified! You can now submit.
            </div>
          )}
          {anyDocFailed && !allDocsVerified && (
            <div style={{ background: '#fdecea', border: '1.5px solid #e74c3c', borderRadius: 10, padding: 12, textAlign: 'center', fontSize: 13, color: '#c0392b' }}>
              ⚠️ Some documents failed. Please re-upload the correct documents.
            </div>
          )}
        </div>

        {/* Submit */}
        <div style={s.card}>
          <div style={s.sectionTitle}>🚀 Step 3 — Submit Application</div>
          <p style={{ fontSize: 13, color: '#888', marginBottom: 16 }}>
            After submission, the admin will review your application and approve it within 1-2 working days.
          </p>
          <button style={{ ...s.btn, opacity: allDocsVerified ? 1 : 0.5 }} type="submit" disabled={loading || !allDocsVerified}>
            {loading ? '⏳ Submitting...' : allDocsVerified ? '✅ Submit Application' : '⚠️ Verify All Documents First'}
          </button>
        </div>
      </form>
    </div>
  );
}
